import { useEffect, useState } from "react";

export default function ReferencePicker({ references, setReferences }) {
    const [query, setQuery] = useState("");
    const [results, setResults] = useState([]);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        if (!query || query.length < 2) {
            setResults([]);
            return;
        }

        const controller = new AbortController();

        const search = async () => {
            setLoading(true);
            try {
                const res = await fetch(
                    `/api/references/search?q=${encodeURIComponent(query)}`,
                    { signal: controller.signal }
                );
                const data = await res.json();
                setResults(Array.isArray(data) ? data : []);
            } catch {}
            finally {
                setLoading(false);
            }
        };

        search();
        return () => controller.abort();
    }, [query]);

    const addReference = (ref) => {
        if (
            references.some(
                r => r.type === ref.type && r.targetId === ref.targetId
            )
        ) return;

        setReferences(prev => [...prev, ref]);
        setQuery("");
        setResults([]);
    };

    const removeReference = (index) => {
        setReferences(prev => prev.filter((_, i) => i !== index));
    };

    return (
        <div className="reference-picker">
            {/* Selected references */}
            <div className="reference-list">
                {references.map((ref, i) => (
                    <span key={i} className="ref-chip">
                        @{ref.displayText}
                        <button onClick={() => removeReference(i)}>×</button>
                    </span>
                ))}
            </div>

            {/* Input */}
            <input
                type="text"
                placeholder="Reference a club, event, or thread…"
                value={query}
                onChange={e => setQuery(e.target.value)}
            />

            {/* Results */}
            {loading && <div className="ref-results">Searching…</div>}

            {results.length > 0 && (
                <div className="ref-results">
                    {results.map((r, i) => (
                        <div
                            key={i}
                            className="ref-result"
                            onClick={() => addReference(r)}
                        >
                            <strong>{r.displayText}</strong>
                            <span> ({r.type})</span>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
}
